@ARTICLE{10.3389/fimmu.2025.1754107,
	author = {Kang R and Sun A and Yang J and Chang L and Sun W and Kou F and Cheng Y},
	title = {Targeting the plasticity of intestinal neutrophils: bidirectional regulation strategies by natural products.},
	journal = {Front Immunol},
	year = {2026},
	abstract = {Historically, neutrophils have been regarded primarily as pro-inflammatory cells, yet recent advancements have revealed their phenotypic heterogeneity and functional plasticity with versatile immunophenotypes. Distinct subpopulations of neutrophils exhibit a functional duality, not only initiating and amplifying inflammation, but also actively promoting tissue restoration in diseases, such as inflammatory bowel disease (IBD), colorectal cancer (CRC) and intestinal infections. They contribute to the formation of a dynamic immune microenvironment in concert with the intestinal microbiota, epithelial cells, and other immune cell types. Current first-line therapies for enteric diseases often lack precision in modulating neutrophil functions. In contrast, natural products including alkaloids, polysaccharides, polyphenols, quinones, and glycosides, as well as microbiota-derived metabolites, exhibit distinct advantages for ability to achieve multi-targeted and bidirectional immunomodulation. These compounds target neutrophil activation, migration, neutrophil extracellular trap formation, cytokine release, oxidative stress, and energy metabolism etc. In this review, we systematically examine the heterogeneity and functional diversity of intestinal neutrophils, highlighting their interaction mechanisms with the surrounding microenvironment. Potential of natural products to modulate neutrophil functions via multi-target strategies has not been fully explored. Moreover, the review discusses novel precision therapeutic approaches based on neutrophil nanotechnology and engineered cell drug delivery. These cutting-edge technologies aim to enhance natural products delivery to inflammatory sites, provide controllable regulation of neutrophil function, and facilitate the degradation of pathological structures. Collectively, the study presents new research directions and theoretical frameworks for intervention of natural products in neutrophils of intestinal immune-related disorders, notably IBD and even CRC.},
	doi = {10.3389/fimmu.2025.1754107},
	pmid = {41601690 [Indexed for MEDLINE]},
	note = {PMC12833395}
}

@ARTICLE{10.3390/nu18020313,
	author = {Kogut Ł and Puchalski C, Katryńska D, Zaguła G},
	title = {The Multidirectional Biological Activity of Resveratrol: Molecular Mechanisms, Systemic Effects and Therapeutic Potential-A Review.},
	journal = {Nutrients},
	year = {2026},
	abstract = {Background/Objectives: Resveratrol is a multi-target polyphenolic stilbene widely studied for its antioxidant, anti-inflammatory, cardioprotective, hepatoprotective, neuroprotective, immunomodulatory and anticancer properties. This review summarizes current evidence on its molecular mechanisms, therapeutic potential, metabolic interactions and biological implications, with particular emphasis on bioavailability, signaling pathways and organ-specific actions. Methods: A comprehensive literature review was conducted focusing on recent in vitro, in vivo and clinical studies evaluating resveratrol's biochemical activity, molecular targets and physiological effects. Special attention was given to oxidative stress regulation, inflammatory signaling, mitochondrial function, metabolic pathways, gut microbiota interactions, and its influence on chronic diseases. Results: Resveratrol modulates several key signaling pathways including NF-κB, SIRT1, AMPK, MAPK, Nrf2 and PI3K/AKT/mTOR. It reduces oxidative stress, inhibits inflammatory cytokines, regulates apoptosis, improves mitochondrial performance, and activates endogenous antioxidant systems. The compound demonstrates protective effects in cardiovascular diseases, hepatic steatosis, neurodegenerative disorders, metabolic dysfunction, and various cancers through anti-inflammatory, anti-proliferative and anti-fibrotic mechanisms. Additionally, resveratrol beneficially alters gut microbiota composition and microbial metabolites, contributing to improved metabolic homeostasis. Despite high intestinal absorption, systemic bioavailability remains low; however, novel nanoformulations significantly enhance its stability and plasma concentrations. Conclusions: Resveratrol exhibits broad therapeutic potential driven by its capacity to regulate oxidative, inflammatory, metabolic and apoptotic pathways at multiple levels. Its pleiotropic activity makes it a promising candidate for prevention and complementary treatment of chronic diseases. Advances in delivery systems and microbiota-derived metabolites may further enhance its clinical applicability.},
	doi = {10.3390/nu18020313},
	pmid = {41599925 [Indexed for MEDLINE]},
	note = {PMC12845197}
}

@ARTICLE{10.1016/j.tjnut.2026.101362,
	author = {Mohammadi H and Ghoflchi S and Abass KS and Hosseini H and Sahebkar A},
	title = {Synergistic Therapeutic Potential of Curcumin and Metformin: a Multipathway Approach to Disease Management.},
	abstract = {Metformin, a first-line pharmacologic agent for type 2 diabetes, exerts its primary antidiabetic effects by suppressing hepatic gluconeogenesis via both AMP-activated protein kinases-dependent and -independent pathways. Beyond glycemic control, metformin exhibits pleiotropic benefits, including improved insulin sensitivity, modulation of gut microbiota, and protection against various metabolic, cardiovascular, renal, neurodegenerative, and inflammatory diseases. However, its clinical use is often limited by gastrointestinal side effects, vitamin B12 deficiency, and rare but serious complications such as lactic acidosis, highlighting the need for adjunctive strategies to enhance efficacy and reduce adverse effects. Curcumin, as a bioactive polyphenol, has garnered significant attention because of its extensive pharmacological activities and excellent safety profile. Curcumin modulates key intracellular signaling pathways, including nuclear factor-kappa B, mitogen-activated protein kinases, and phosphatidylinositol 3-kinase/protein kinase B, providing anti-inflammatory, antioxidant, anticancer, and metabolic regulatory effects. Nonetheless, its clinical application is constrained by poor bioavailability because of limited absorption, rapid metabolism, and systemic elimination. Recent evidence suggests that coadministration of metformin and curcumin yields synergistic therapeutic outcomes in diverse disease models. This combination improves glycemic control, mitigates oxidative stress and inflammation, and provides organ-protective effects, particularly in the liver, heart, and skin. Furthermore, it shows promise in cancer prevention and therapy, polycystic ovary syndrome management, and pain modulation, with enhanced outcomes when delivered via nanoparticle-based systems. This review aims to provide a comprehensive analysis of the combined therapeutic potential of metformin and curcumin across a spectrum of pathological conditions.},
	doi = {10.1016/j.tjnut.2026.101362},
	pmid = {41539435 [Indexed for MEDLINE]}
}

@ARTICLE{10.3389/fnut.2025.1696289,
	author = {Sun M and Zang D and Chen J},
	title = {Bioactive components and delivery strategies of food-medicine homologous substances in lung cancer therapy: current advances and clinical translation.},
	abstract = {Lung cancer remains the leading cause of cancer-related mortality worldwide, challenged by drug resistance, treatment toxicities, and limited efficacy. Recently, food-medicine homologous (FMH) substances have gained attention as adjunctive therapies due to their multi-target effects, low toxicity, and favorable safety profiles. As the "food as medicine" paradigm integrates into health policies, a comprehensive understanding of FMH in lung cancer therapy as a form of nutrition-based adjuvant therapy is increasingly relevant and timely. This review summarizes the anti-lung cancer mechanisms of FMH-derived bioactive compounds-such as polysaccharides, saponins, polyphenols, alkaloids, and essential oils-focusing on their roles in cell cycle regulation, apoptosis induction, immune modulation, and resistance reversal. To address poor bioavailability, we highlight recent advances in nanodelivery systems that enhance therapeutic efficacy. Moreover, we examine nutritional modulation of gut microbiota under the gut-lung axis framework as a novel strategy in lung cancer treatment. By integrating preclinical evidence with translational studies, this review evaluates the clinical potential and future directions of FMH-based therapies. The aim is to provide a theoretical basis for optimizing integrative Chinese-Western approaches and advancing personalized nutrition-oriented strategies in lung cancer care.},
	doi = {10.3389/fnut.2025.1696289},
	pmid = {41473195},
	note = {PMC12747675}
}

@ARTICLE{10.1186/s13046-025-03608-z,
	author = {Liu D and Li R and Li M and Liang Y and Wang Z and Sun Y and Ge P},
	title = {Colon-Targeted astragalus polysaccharide nanoparticles prevent NAFLD-Driven hepatocarcinogenesis via microbiota remodeling and NF-κB Inhibition.},
	journal = {J Exp Clin Cancer Res},
	year = {2025},
	abstract = {Hepatocellular carcinoma (HCC), often arising from liver fibrosis in nonalcoholic fatty liver disease (NAFLD), remains a leading cause of cancer-related death. Targeting the gut-liver axis offers new therapeutic opportunities to prevent this progression. In this study, colon-targeted chitosan/pectin-based nanoparticles loaded with Astragalus polysaccharide (APs-CS/PT-NPs) were developed to modulate gut microbiota and inhibit liver tumorigenesis. The nanoparticles exhibited robust physicochemical stability and pH-responsive release. In vivo, oral administration of APs-CS/PT-NPs attenuated hepatic steatosis, reduced inflammatory cytokines, and suppressed NAFLD-induced HCC development. 16 S rRNA sequencing revealed restoration of microbial diversity and enhanced production of short-chain fatty acids, especially acetate. Mechanistically, transcriptomic profiling and functional analysis identified acetate as a key mediator, acting via G-protein-coupled receptor 43 (GPR43) to inhibit the NF-κB pathway. These results highlight the therapeutic potential of APs-CS/PT-NPs in modulating the gut-liver axis, rebalancing intestinal microbiota, and suppressing pro-inflammatory signaling. This nanoparticle-based strategy offers a promising food-derived preventive intervention for liver fibrosis-HCC transition.},
	doi = {10.1186/s13046-025-03608-z},
	pmid = {41422246 [Indexed for MEDLINE]},
	note = {PMC12751668}
}

@ARTICLE{10.1016/j.mtbio.2025.102509,
	author = {Hou Y and Wu J and Jin B and Zhang Y and Zhang J and Zhang Y and Gao J and Sun X and Dong Z},
	title = {Preparation of hierarchically targetable Astragalus polysaccharide lipid nanoparticles and study on their therapeutic effect on orthotopic colon cancer.},
	journal = {Mater Today Bio},
	year = {2025},
	abstract = {An oral targeted drug delivery system based on polysaccharides can successfully target and deliver drugs to diseased sites in the colon, optimize therapeutic effects, and reduce adverse reactions. In this study, we developed a multifunctional, orally administered, colon-targeted, drug-loaded nanoparticles (SN38-SLN-APS NPs), based on Astragalus polysaccharides (APS), and loaded it with the anti-tumor drug 7-ethyl-10-hydroxycamptothecin (SN38). The surfaces of the SN38-SLN-APS NPs were modified using APS, APS undergoes almost no degradation in the stomach or small intestine, thereby protecting SN38-SLN-APS NPs and enabling its delivery into the colon. APS possess a negative charge, which can diminish the adsorption of mucoproteins and facilitate the translocation of SN38-SLN-APS NPs through the mucus layer. Upon reaching the colon, the SN38-SLN-APS NPs are destroyed by colonic bacteria. This approach enhances the gut microbiota in colon cancer by augmenting the amount and diversity of intestinal bacteria. We functionalized liposomes with the tumor-homing and -penetrating peptide iRGD; NPs treated with iRGD can augment drug accumulation at tumor locations while diminishing retention in normal tissues, hence producing anti-tumor effects. This study developed a colon-specific multifunctional NPs. They may accurately target the colon and attach to tumor cells, so successfully preventing the early absorption of medicines in the upper digestive system. SN38-SLN-APS NPs effectively safeguard the medicine against degradation by gastric acid and digestive enzymes, ensuring the active components reach the target site intact. This novel technique provides a new therapy avenue for colorectal cancer, anticipated to markedly improve therapeutic efficacy and diminish adverse effects.},
	doi = {10.1016/j.mtbio.2025.102509},
	pmid = {41322144},
	note = {PMC12663652}
}

@ARTICLE{10.1016/j.phymed.2025.157509,
	author = {Mu W and Yestekbayeva D and Twum B and Wan MLY},
	title = {A comprehensive review of six dietary polyphenols in colorectal cancer: Pharmacokinetics, mechanism and therapeutic potentials.},
	journal = {Phytomedicine},
	year = {2025},
	abstract = {BACKGROUND: Colorectal cancer (CRC) remains a major global health challenge with high morbidity and mortality despite advances in detection and treatment. Dietary polyphenols are secondary metabolites widely found in plant-derived foods and beverages, and have gained attention for their potential in CRC prevention and therapy due to their diverse biological activities. METHODS: This review synthesizes findings published between 01 January 2019 and 31 May 2025 on the preventive and therapeutic effects of six common dietary polyphenols in CRC, based on in vitro, animal and human studies retrieved from PubMed, Scopus and Google Scholar. A total of 333 eligible papers were included. Pharmacokinetic properties and drug-likeness of dietary polyphenols were evaluated using the SwissADME. Toxicity prediction of polyphenols was done by the ProTox 3.0. RESULTS: Despite their structural diversity, polyphenols share key anticancer mechanisms against CRC. Their effects are primarily mediated through induction of cell cycle arrest, inhibition of oncogenic pathways involved in proliferation and angiogenesis, promotion of apoptosis or autophagy, inhibition of inflammation and oxidative stress, and modulation of the gut microbiota. Absorption, Distribution, Metabolism, Excretion and Toxicity (ADMET) analysis indicates generally favorable pharmacological properties such as high gastrointestinal absorption, moderate lipophilicity, and selective cytochrome P450 enzyme inhibition, and an overall good safety profile for most studied polyphenols. However, their clinical application is hindered by poor bioavailability, metabolic instability and dosage variability. CONCLUSION: Dietary polyphenols hold promise as adjuncts to CRC therapies. Addressing pharmacokinetic limitations through nanoformulations, combination strategies and well-designed clinical trials is critical to unlock their full therapeutic value and ensure safe and effective application.},
	doi = {10.1016/j.phymed.2025.157509},
	pmid = {41289747 [Indexed for MEDLINE]}
}

@ARTICLE{10.3389/fimmu.2025.1653378,
	author = {Saad AM and Mohammed DM and Alkafaas SS and Ghosh S and Negm SH and Salem HM and Fahmy MA and Semary HE and Ibrahim EH and AbuQamar SF and El-Tarabily KA and El-Saadony MT},
	title = {Dietary polyphenols and human health: sources, biological activities, nutritional and immunological aspects, and bioavailability- a comprehensive review.},
	journal = {Front Immunol},
	year = {2025},
	abstract = {Dietary polyphenols, particularly flavonoids, have been extensively recognized for their role as a source of bioactive molecules that contribute to the prevention of various diseases, including cancer. This review aims to provide a comprehensive overview of dietary polyphenols by examining their sources, classification, mechanisms of action, and biological effects, with a particular emphasis on their nutritional and immunological roles. It also highlights the need for ongoing research into preventive strategies and the development of improved therapeutic options. Despite their broad spectrum of antioxidant, anti-inflammatory, neuroprotective, antimicrobial, anti-diabetic, and anti-cancer activities, the therapeutic application of polyphenols is significantly hindered by their inherently poor bioavailability. This limitation poses a substantial challenge, as it prevents polyphenols from achieving the systemic concentration necessary to elicit a therapeutic effect. This review critically evaluates current strategies, including nano- and liposomal-based delivery systems. Liposomal systems play a crucial role in enhancing the bioavailability of polyphenols by encapsulating these compounds in lipid bilayers. This encapsulation improves the solubility and stability of polyphenols, protects them from environmental degradation and rapid metabolism, and facilitates their controlled release and absorption in the body. Liposomes enable polyphenols to better traverse biological membranes and protect them from unfavorable conditions in the gastrointestinal tract, resulting in greater systemic availability and improved therapeutic efficacy compared to non-encapsulated forms. The current review also explores the modulatory impact of polyphenols on the immune system, their influence on gut microbiota, and their implications across various life stages, from infancy to aging, as well as in athletic performance and dermatological health. Future directions are proposed to optimize their clinical utility, including standardized dosing, improved delivery technologies, and targeted nutritional interventions. Ultimately, integrating polyphenols into daily dietary practices may offer promising avenues for enhancing immune resilience and preventing chronic diseases.},
	doi = {10.3389/fimmu.2025.1653378},
	pmid = {41256860 [Indexed for MEDLINE]},
	note = {PMC12620276}
}

@ARTICLE{10.7150/jca.118694,
	author = {Ren S and Lu L and Su H and Li Z and Li S and Pan J and Liu Y and Ji G and Xu H},
	title = {Regulating arachidonic acid metabolism: a novel strategy to prevent colorectal inflammatory cancer transformation.},
	abstract = {Colorectal cancer (CRC) ranks among the leading causes of cancer-related morbidity and mortality worldwide, with colitis-associated colorectal cancer (CAC) driven by inflammatory cancer transformation. Arachidonic acid (AA), a key ω-6 polyunsaturated fatty acid, and its metabolites, including prostaglandins (PGs) and leukotrienes (LTs), play pivotal roles in this process by modulating inflammation, immune responses, and the intestinal microenvironment. Notably, a multi-enzyme co-expression nanoplatform integrating lipoxygenase (LOX) and phospholipase A2 (PLA2) has been developed, synergistically inducing immunogenic ferroptosis and upregulating AA expression to enhance CD8+ T cell-mediated anti-tumor immunity. Additionally, dual COX-2/soluble epoxide hydrolase (sEH) inhibitors, such as PTUPB, demonstrate enhanced anti-tumor activity and reduced toxicity when combined with cisplatin, offering a promising approach to mitigate gastrointestinal side effects of nonsteroidal anti-inflammatory drugs (NSAIDs). Furthermore, natural products like ginsenoside Rk3 and berberine have been identified to regulate AA metabolism and gut microbiota, alleviating CAC by modulating lipid peroxidation and inflammatory pathways. This review synthesizes these innovative findings, highlighting the role of AA metabolism in maintaining intestinal homeostasis, promoting inflammatory cancer transformation, and serving as a therapeutic target to inhibit CAC progression, thus providing new insights into its prevention and treatment.},
	doi = {10.7150/jca.118694},
	pmid = {41210682},
	note = {PMC12595249}
}

@ARTICLE{10.1016/j.semcancer.2025.10.006,
	author = {Xia F and Yi Q and Xu Z and Zhou Z and Tang H and Zhang K and Yan Y},
	title = {Microbial modulation as a game changer: Boosting immunotherapy efficacy in breast cancer.},
	journal = {Semin Cancer Biol},
	year = {2025},
	abstract = {Breast cancer is generally regarded as an immunologically cold tumor, characterized by limited T cell infiltration and poor responsiveness to immune checkpoint inhibitors. Increasing evidence suggests that the human microbiome, including both gut and tumor-associated microbial communities, serves as a critical regulator of systemic and local antitumor immunity, with potential to convert inert tumors into immune-responsive states. Gut microbiota influence systemic immune homeostasis through metabolites such as lipids, lactic acid, and trimethylamine N-oxide, which modulate T lymphocytes, dendritic cells, leukocytes, and stromal components. Tumor-resident microbiota further shape the tumor immune microenvironment by regulating CD4+ and CD8+ T cells, NKT cells, Tregs, and macrophages, thereby impacting the efficacy of immune checkpoint blockade. Emerging strategies to sensitize cold breast tumors through microbiome modulation include dietary phytochemicals, bariatric surgery induced microbial shifts, probiotics and postbiotics, polyvalent microbial antigen vaccines, and nanotechnology-based platforms. Clinical challenges remain, particularly interindividual microbial heterogeneity, safety and regulatory considerations, and the need for reliable microbial and immune biomarkers. This review summarizes current advances in microbiota-immune interactions in breast cancer and discusses opportunities for microbiome-targeted strategies to enhance immunotherapy outcomes.},
	doi = {10.1016/j.semcancer.2025.10.006},
	pmid = {41197754 [Indexed for MEDLINE]}
}
